import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate, Link as RouterLink } from 'react-router-dom';
import {
  Card, CardContent, TextField, Button, Typography, Box,
  InputAdornment, IconButton, Alert, CircularProgress,
  LinearProgress, Collapse, Divider, Link, Checkbox,
  FormControlLabel, Snackbar, Slide, Paper,
} from '@mui/material';
import {
  Visibility, VisibilityOff, PersonOutline, LockOutlined,
  CheckCircleOutline, ErrorOutline, LoginOutlined,
} from '@mui/icons-material';
import { login, clearError, selectAuth } from '../../store/slices/authSlice';

// Constants
const LOGO_PATH = "./logo.png";
const SNACKBAR_AUTO_HIDE_DURATION = 6000;
const REDIRECT_DELAY = 1500;
const ERROR_PERSISTENCE_DURATION = 10000;

function SlideTransition(props) {
  return <Slide {...props} direction="up" />;
}

const SignInCard = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { isLoading, error, isAuthenticated } = useSelector(selectAuth);
  
  // Form state
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  
  // UI state
  const [showSuccess, setShowSuccess] = useState(false);
  const [snackbarOpen, setSnackbarOpen] = useState(false);
  const [displayError, setDisplayError] = useState('');
  const [touchedFields, setTouchedFields] = useState({
    username: false,
    password: false,
  });
  
  // Refs
  const redirectTimerRef = useRef(null);
  const errorTimeoutRef = useRef(null);

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      if (redirectTimerRef.current) clearTimeout(redirectTimerRef.current);
      if (errorTimeoutRef.current) clearTimeout(errorTimeoutRef.current);
    };
  }, []);

  // Load persisted error from session storage
  useEffect(() => {
    const savedError = sessionStorage.getItem('last_auth_error');
    const timestamp = sessionStorage.getItem('last_auth_error_time');
    
    if (savedError && timestamp) {
      const now = Date.now();
      if (now - parseInt(timestamp) < ERROR_PERSISTENCE_DURATION) {
        setDisplayError(savedError);
        setSnackbarOpen(true);
      }
    }
  }, []);

  // Handle auth errors
  useEffect(() => {
    if (error) {
      const errorMessage = error?.message || (typeof error === 'string' ? error : 'Login failed. Please check your credentials.');
      setDisplayError(errorMessage);
      setSnackbarOpen(true);
      
      // Persist error for page refresh scenarios
      sessionStorage.setItem('last_auth_error', errorMessage);
      sessionStorage.setItem('last_auth_error_time', Date.now().toString());
      
      // Clear error after duration
      if (errorTimeoutRef.current) clearTimeout(errorTimeoutRef.current);
      errorTimeoutRef.current = setTimeout(() => {
        dispatch(clearError());
      }, 5000);
    }
  }, [error, dispatch]);

  // Handle successful authentication
  useEffect(() => {
    if (isAuthenticated) {
      setShowSuccess(true);
      sessionStorage.removeItem('last_auth_error');
      sessionStorage.removeItem('last_auth_error_time');
      
      // Save remember me preference
      if (rememberMe) {
        localStorage.setItem('remembered_username', username);
      } else {
        localStorage.removeItem('remembered_username');
      }
      
      // Redirect after delay
      redirectTimerRef.current = setTimeout(() => {
        navigate('/dashboard', { replace: true });
      }, REDIRECT_DELAY);
    }
  }, [isAuthenticated, navigate, rememberMe, username]);

  // Load remembered username on mount
  useEffect(() => {
    const rememberedUsername = localStorage.getItem('remembered_username');
    if (rememberedUsername) {
      setUsername(rememberedUsername);
      setRememberMe(true);
    }
  }, []);

  // Validation functions
  const validateForm = useCallback(() => {
    const errors = {};
    
    if (!username.trim()) {
      errors.username = 'Username or email is required';
    } else if (username.length < 3) {
      errors.username = 'Username must be at least 3 characters';
    }
    
    if (!password) {
      errors.password = 'Password is required';
    } else if (password.length < 6) {
      errors.password = 'Password must be at least 6 characters';
    }
    
    return errors;
  }, [username, password]);

  const formErrors = validateForm();
  const isValid = Object.keys(formErrors).length === 0;
  const isDisabled = isLoading || showSuccess;

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Mark all fields as touched
    setTouchedFields({ username: true, password: true });
    
    // Validate before submission
    if (!isValid) return;
    
    try {
      dispatch(clearError());
      await dispatch(login({ username: username.trim(), password })).unwrap();
    } catch (err) {
      // Error is handled by the error useEffect
      console.error('Login failed:', err?.message || err);
    }
  };

  const handleFieldChange = (field, value) => {
    if (field === 'username') setUsername(value);
    if (field === 'password') setPassword(value);
    
    // Clear field-specific error when user starts typing
    if (error?.fieldErrors?.[field]) {
      dispatch(clearError());
    }
  };

  const handleBlur = (field) => {
    setTouchedFields(prev => ({ ...prev, [field]: true }));
  };

  const handleCloseSnackbar = (event, reason) => {
    if (reason === 'clickaway') return;
    setSnackbarOpen(false);
    sessionStorage.removeItem('last_auth_error');
    sessionStorage.removeItem('last_auth_error_time');
    dispatch(clearError());
  };

  const getFieldError = (field) => {
    if (!touchedFields[field]) return undefined;
    return formErrors[field] || error?.fieldErrors?.[field];
  };

  return (
    <>
      <Card
        elevation={0}
        sx={{
          width: { xs: '100%', sm: 440, md: 480 },
          maxWidth: '95vw',
          borderRadius: 4,
          boxShadow: '0 20px 40px rgba(0,0,0,0.1), 0 4px 12px rgba(0,0,0,0.06)',
          mx: 'auto',
          overflow: 'hidden',
          transition: 'transform 0.2s ease-in-out',
          '&:hover': {
            transform: 'translateY(-4px)',
          },
        }}
      >
        {/* Progress Indicator */}
        <Box sx={{ height: 4 }}>
          {isLoading && <LinearProgress sx={{ height: 4 }} />}
          {showSuccess && (
            <LinearProgress 
              variant="determinate" 
              value={100} 
              color="success" 
              sx={{ height: 4, transition: 'none' }}
            />
          )}
        </Box>

        <CardContent sx={{ p: { xs: 4, sm: 5 } }}>
          {/* Header Section with Logo */}
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Box
              component="img"
              src={LOGO_PATH}
              alt="Electoral Commission Logo"
              onError={(e) => {
                e.target.onerror = null;
                e.target.style.display = 'none';
              }}
              sx={{ 
                width: 80, 
                height: 'auto', 
                mb: 2,
                filter: 'drop-shadow(0px 4px 8px rgba(0,0,0,0.1))',
                transition: 'transform 0.2s ease',
                '&:hover': {
                  transform: 'scale(1.05)',
                },
              }}
            />
            <Typography 
              variant="h4" 
              fontWeight={800} 
              sx={{ 
                lineHeight: 1.2, 
                mb: 1,
                background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
                backgroundClip: 'text',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
              }}
            >
              Welcome Back
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Commission Action Tracker
            </Typography>
          </Box>

          {/* Success Alert */}
          <Collapse in={showSuccess}>
            <Alert 
              severity="success" 
              icon={<CheckCircleOutline />} 
              sx={{ mb: 3, borderRadius: 2 }}
            >
              Login successful! Redirecting to dashboard...
            </Alert>
          </Collapse>

          {/* Login Form */}
          <form onSubmit={handleSubmit} noValidate>
            <TextField
              fullWidth
              label="Username or Email"
              variant="outlined"
              value={username}
              onChange={(e) => handleFieldChange('username', e.target.value)}
              onBlur={() => handleBlur('username')}
              margin="normal"
              disabled={isDisabled}
              autoFocus
              error={!!getFieldError('username')}
              helperText={getFieldError('username')}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <PersonOutline color="action" />
                  </InputAdornment>
                ),
              }}
              sx={{ mb: 2 }}
            />

            <TextField
              fullWidth
              label="Password"
              variant="outlined"
              type={showPassword ? 'text' : 'password'}
              value={password}
              onChange={(e) => handleFieldChange('password', e.target.value)}
              onBlur={() => handleBlur('password')}
              margin="normal"
              disabled={isDisabled}
              error={!!getFieldError('password')}
              helperText={getFieldError('password')}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <LockOutlined color="action" />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton 
                      onClick={() => setShowPassword(prev => !prev)} 
                      disabled={isDisabled} 
                      edge="end"
                      aria-label={showPassword ? 'Hide password' : 'Show password'}
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />

            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mt: 1 }}>
              <FormControlLabel
                control={
                  <Checkbox 
                    checked={rememberMe} 
                    onChange={(e) => setRememberMe(e.target.checked)} 
                    disabled={isDisabled} 
                    color="primary" 
                  />
                }
                label={<Typography variant="body2">Remember me</Typography>}
              />
              <Link 
                component="button" 
                type="button" 
                variant="body2" 
                underline="hover" 
                onClick={() => navigate('/forgot-password')}
                sx={{ fontWeight: 500 }}
              >
                Forgot password?
              </Link>
            </Box>

            <Button
              type="submit"
              fullWidth
              variant="contained"
              size="large"
              disabled={isDisabled || (!isValid && touchedFields.username && touchedFields.password)}
              startIcon={!isLoading && !showSuccess && <LoginOutlined />}
              sx={{ 
                mt: 4, 
                py: 1.5, 
                textTransform: 'none', 
                fontSize: '1rem', 
                fontWeight: 600,
                borderRadius: 2,
                background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
                '&:hover': {
                  background: 'linear-gradient(135deg, #16345e 0%, #1f4175 100%)',
                },
              }}
            >
              {isLoading ? (
                <><CircularProgress size={20} sx={{ mr: 1.5 }} color="inherit" />Signing in...</>
              ) : showSuccess ? (
                'Redirecting...'
              ) : (
                'Sign In'
              )}
            </Button>
          </form>

          <Divider sx={{ my: 4 }}>
            <Typography variant="caption" color="text.secondary">OR</Typography>
          </Divider>

          <Box sx={{ textAlign: 'center' }}>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Don't have an account?
            </Typography>
            <Button 
              component={RouterLink} 
              to="/signup" 
              variant="outlined" 
              fullWidth 
              size="large" 
              sx={{ 
                py: 1.5, 
                textTransform: 'none',
                borderRadius: 2,
                borderWidth: 2,
                '&:hover': {
                  borderWidth: 2,
                },
              }}
            >
              Create New Account
            </Button>
          </Box>
        </CardContent>
      </Card>

      {/* Error Snackbar */}
      <Snackbar
        open={snackbarOpen}
        autoHideDuration={SNACKBAR_AUTO_HIDE_DURATION}
        onClose={handleCloseSnackbar}
        TransitionComponent={SlideTransition}
        anchorOrigin={{ vertical: 'top', horizontal: 'center' }}
      >
        <Alert 
          onClose={handleCloseSnackbar} 
          severity="error" 
          variant="filled"
          icon={<ErrorOutline />}
          sx={{ 
            width: '100%', 
            boxShadow: 6, 
            borderRadius: 2,
            alignItems: 'center',
          }}
        >
          {displayError || 'Login failed. Please check your credentials.'}
        </Alert>
      </Snackbar>
    </>
  );
};

export default SignInCard;